import type { ScaleLinear, ScaleSymLog } from 'd3-scale';

import type {
  ConvertibleUnit,
  FormatOptions,
  Unit,
} from '@dynatrace-sdk/units';

import type { IntentProps } from '../../../core/slots/Intent/Intent.js';
import type { BehaviorTrackingProps } from '../../../core/types/behavior-tracking-props.js';
import { MaskingProps } from '../../../core/types/masking-props.js';
import { StylingProps } from '../../../core/types/styling-props.js';
import type { TruncationMode } from '../../../typography/text-ellipsis/TextEllipsis.js';
import type {
  ColorPalette,
  ColorPaletteMode,
  CustomColorPalette,
} from '../../core/types/color-palette.js';
import { ColorRuleProps } from '../../core/types/color-rule.js';
import type { Formatter } from '../../core/types/formatter.js';
import type { LegendPosition, LegendProps } from '../../core/types/legend.js';
import type {
  AxisScaleType,
  ValueRepresentation,
} from '../../core/types/scales.js';
import type { SeriesActionsTemplate } from '../../core/types/series-actions-template.js';
import {
  ChartToolbarConfig,
  InternalChartToolbarConfigured,
} from '../../core/types/toolbar.js';
import type { WithId } from '../../core/types/with-id.js';
import type { CategoricalBarChartThresholdIndicatorProps } from '../slots/ThresholdIndicator.js';

//region Common
/**
 * Defines whether the item is displayed horizontally or vertically.
 * @public
 */
export const layoutOptions = ['horizontal', 'vertical'] as const;
/**
 * @public
 */
export type Layout = (typeof layoutOptions)[number];

/**
 * Strategy used for grouping the bars in a bar chart.
 * @public
 */
export const groupModeOptions = ['grouped', 'stacked'] as const;
/**
 * @public
 */
export type GroupMode = (typeof groupModeOptions)[number];

/**
 * Tooltip variant. 'single' displays only the closest category, and 'grouped' all the categories within a category.
 * @public
 */
export const categoricalChartTooltipVariantOptions = [
  'single',
  'grouped',
] as const;
/**
 * @public
 */
export type CategoricalChartTooltipVariant =
  (typeof categoricalChartTooltipVariantOptions)[number];

//endregion

//region Slots
/**
 * @internal
 */
export interface CategoricalBarChartSlots {
  legend: {
    position?: LegendPosition;
    hidden?: boolean;
  };
  tooltip: {
    variant?: CategoricalChartTooltipVariant;
  };
  valueAxis: {
    label?: string;
    min?: number;
    max?: number;
    /**
     * Handler that is called for every tick value to be formatted.
     */
    formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
    /** The scale of the value axis. */
    scale?: AxisScaleType;
  };
  categoryAxis: {
    tickLabelLayout?: Layout;
    label?: string;
  };
  thresholds: CategoricalBarChartThresholdIndicatorProps[];
  toolbar: Partial<CategoricalBarChartToolbarInternalConfigured>;
  colorRules: ColorRuleProps[];
  intents: InternalCategoricalBarChartConfig['intents'];
}

//endregion

//region Configuration
/**
 * @public
 */
export interface CategoricalBarChartConfiguration {
  /**
   * Whether the bars are displayed in a 'vertical' or 'horizontal' layout.
   * @defaultValue 'vertical'
   */
  layout?: Layout;
  /**
   * Strategy used for grouping the bars within a category. "stacked" will mount one on top of each other, and "grouped" will place one next to the other
   * @defaultValue 'stacked'
   */
  groupMode?: GroupMode;
  /**
   * Color palette to be used for the bar category.
   * @defaultValue "categorical"
   */
  colorPalette?: ColorPalette | CustomColorPalette;
  /**
   * The way values are represented. "absolute" will display the value as it is, and "relative" displays a percentage value considering the other dimensions values within a categories.
   * @defaultValue "absolute"
   */
  valueRepresentation?: ValueRepresentation;
  /**
   * Tooltip config for the chart
   */
  tooltip?: {
    /**
     * Tooltip variant. 'single' displays only the closest category, and 'grouped' all the categories within a category.
     */
    variant?: CategoricalChartTooltipVariant;
  };
  /**
   * Config for the axis holding the category
   */
  categoryAxis?: {
    /**
     * Whether the tick labels are displayed in a 'vertical' or 'horizontal' layout.
     * @defaultValue 'horizontal'
     */
    tickLabelLayout?: Layout;
    // Optional axis label
    label?: string;
  };
  /**
   * Config for the axis holding the category values
   */
  valueAxis?: {
    // Optional axis label
    label?: string;
    // Min value to be represented on a value axis
    min?: number;
    // Max value to be represented on a value axis
    max?: number;
    /**
     * Handler that is called for every tick value to be formatted.
     */
    formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
    /** The scale of the value axis. */
    scale?: AxisScaleType;
  };
  // Config for the chart legend config.
  legend?: {
    /**
     * Defines the position where to show the chart legend.
     * @defaultValue "auto"
     */
    position?: LegendPosition;
    /**
     * Whether the legend is hidden or shown
     * @defaultValue "false" - the legend is shown
     */
    hidden?: boolean;
  };
  /**
   * Truncation mode to use (start, middle, end)
   * @defaultValue 'middle'
   */
  truncationMode?: TruncationMode;
  /**
   * Mode in which bars are colored when single dimension data is shown
   * @defaultValue "multi-colored" - each bar gets a color in the palette sequentially
   */
  colorPaletteMode?: ColorPaletteMode;
  /**
   * ThresholdIndicator configuration for the categorical bar chart value axis.
   */
  thresholdIndicators?: CategoricalBarChartThresholdConfiguration[];
  /**
   * Config for the chart toolbar
   */
  toolbar?: CategoricalBarChartToolbarConfiguration;
  /**
   * Color rules to apply to the bars
   */
  colorRules?: ColorRuleProps[];
}

/**
 * Config type holding all the required config used in the categorical bar chart. Considers that the defaults have already been applied.
 * @public
 */
export type RequiredCategoricalBarChartConfiguration =
  Required<CategoricalBarChartConfiguration> & {
    tooltip: CategoricalBarChartTooltipConfiguration;
    legend: CategoricalBarChartLegendConfiguration;
    categoryAxis: CategoricalBarChartCategoryAxisConfiguration;
    thresholdIndicators: InternalCategoricalBarChartThresholdConfiguration[];
    toolbar?: CategoricalBarChartToolbarConfiguration;
  };

/**
 * @internal
 */
export type InternalCategoricalBarChartConfig = Omit<
  RequiredCategoricalBarChartConfiguration,
  'toolbar'
> & {
  intents: IntentProps[];
  toolbar: CategoricalBarChartToolbarInternalConfigured &
    Required<
      Pick<
        CategoricalBarChartToolbarInternalConfigured,
        'placement' | 'hidden' | 'downloadData'
      >
    >;
};

/**
 * @public
 */
export interface CategoricalBarChartTooltipConfiguration {
  variant: CategoricalChartTooltipVariant;
}

/**
 * @public
 */
export type CategoricalBarChartLegendConfiguration = LegendProps;

/**
 * @public
 */
export interface CategoricalBarChartValueAxisConfiguration {
  label?: string;
  min?: number;
  max?: number;
  /**
   * Handler that is called for every tick value to be formatted.
   */
  formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
  /** The scale of the value axis. */
  scale?: AxisScaleType;
}

/**
 * @public
 */
export type CategoricalBarChartToolbarConfiguration = ChartToolbarConfig & {
  hidden?: boolean;
};

/**
 * @internal
 */
export interface CategoricalBarChartToolbarInternalConfigured
  extends InternalChartToolbarConfigured {
  hidden?: boolean;
}

/**
 * @public
 */
export interface CategoricalBarChartCategoryAxisConfiguration {
  label?: string;
  tickLabelLayout: Layout;
  /** Max size in pixels for the category axis. Size depends on the position this axis is assigned to – left axis will use width, bottom axis will use height.
   *  If there's no enough space for this maxSize, category axis will only take the available space for it.
   */
  maxSize?: number;
}

/**
 * @public
 */
export type CategoricalBarChartThresholdConfiguration =
  CategoricalBarChartThresholdIndicatorProps;

/**
 * @public
 */
export type InternalCategoricalBarChartThresholdConfiguration =
  WithId<CategoricalBarChartThresholdConfiguration>;
//endregion

//region Props
// TODO: ADES-5109 we need to support Unit in the categoricalBarChart
/**
 * @public
 * @deprecated CategoricalUnit is deprecated, use string | Unit instead.
 */
export type CategoricalUnit = string;

/**
 * @public
 */
export interface CategoricalBarChartData extends Record<string, unknown> {
  category: string;
  value: number | Record<string, number>;
  // eslint-disable-next-line @typescript-eslint/no-deprecated
  unit?: CategoricalUnit | string | Unit;
  /* @deprecated - use color rules instead. This key will be removed in a future release */
  color?: string;
}

/**
 * Ref of the Categorical bar chart
 * @public
 */
export interface CategoricalBarChartRef {
  /** Chart div element */
  element: HTMLDivElement | null;
  /** Returns the current serialized config of the categorical bar chart .*/
  getConfig: () => string;
  /** Downloads map raw data .*/
  downloadData: () => void;
}

/**
 * @public
 */
export interface CategoricalBarChartProps
  extends StylingProps,
    MaskingProps,
    BehaviorTrackingProps {
  /**
   * Data object for the categorical bar chart
   */
  data: CategoricalBarChartData[];
  /**
   * Chart height. When a number is specified, is considered as pixels, otherwise a valid height string is expected.
   * @defaultValue 300px
   */
  height?: number | string;
  /**
   * Chart width. When a number is specified, it's treated as pixels,
   * otherwise a valid width string is expected.
   * @defaultValue 100%
   */
  width?: number | string;
  /**
   * Whether the bars are displayed in a 'vertical' or 'horizontal' layout.
   * @defaultValue 'vertical'
   */
  layout?: Layout;
  /**
   * Strategy used for grouping the bars within a category. "stacked" will mount one on top of each other, and "grouped" will place one next to the other
   *@defaultValue 'stacked'
   */
  groupMode?: GroupMode;
  /**
   * Color palette to be used for the bar category.
   * @defaultValue "categorical"
   */
  colorPalette?: ColorPalette | CustomColorPalette;
  /**
   * The way values are represented. "absolute" will display the value as it is, and "relative" displays a percentage value considering the other dimensions values within a category.
   * @defaultValue "absolute"
   */
  valueRepresentation?: ValueRepresentation;
  /**
   * Category actions to be shown in the legend and tooltip actions
   */
  seriesActions?: (series: Record<string, unknown>) => SeriesActionsTemplate;
  /**
   * Truncation mode to use (start, middle, end)
   * Applied to all the parts that truncate text.
   * @defaultValue 'middle'
   */
  truncationMode?: TruncationMode;
  /**
   * Mode in which bars are colored when single dimension data is shown
   * @defaultValue "single-color" - each bar gets the same color
   */
  colorPaletteMode?: ColorPaletteMode;
  /** Show the loading indicator when truthy.
   * @defaultValue false
   */
  loading?: boolean;
}

/**
 * @public
 */
export interface CategoricalBarChartTooltipProps {
  /**
   * Tooltip variant. 'single' displays only the closest category, and 'grouped' all the category within a category.
   */
  variant: CategoricalChartTooltipVariant;
}

/**
 * @public
 */
export interface CategoricalBarChartCategoryAxisProps {
  /**
   * Whether the tick labels are displayed in a 'vertical' or 'horizontal' layout.
   * @defaultValue 'horizontal'
   */
  tickLabelLayout?: Layout;
  // Optional axis label
  label?: string;
  /** Max size in pixels for the category axis. Size depends on the position this axis is assigned to – left axis will use width, bottom axis will use height.
   *  If there's no enough space for this maxSize, category axis will only take the available space for it.
   */
  maxSize?: number;
}

/**
 * @public
 */
export interface CategoricalBarChartValueAxisProps {
  // Optional axis label
  label?: string;
  // Min value to be represented on a value axis
  min?: number;
  // Max value to be represented on a value axis
  max?: number;
  /**
   * Handler that is called for every tick value to be formatted.
   */
  formatter?: Formatter | FormatOptions<Unit, ConvertibleUnit>;
  /** The scale of the value axis. */
  scale?: AxisScaleType;
}

/**
 * @public
 */
export type CategoricalBarChartLegendProps = LegendProps;

/**
 * @internal
 */
export type CategoricalValueScales =
  | ScaleLinear<number, number>
  | ScaleSymLog<number, number>;
